import{_ as e,o as a,c as r,a2 as o}from"./chunks/framework.B08aFN1B.js";const p=JSON.parse('{"title":"Time Machine","description":"","frontmatter":{},"headers":[],"relativePath":"history.md","filePath":"history.md","lastUpdated":null}'),i={name:"history.md"};function s(n,t,d,h,l,c){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="Time-Machine" tabindex="-1">Time Machine <a class="header-anchor" href="#Time-Machine" aria-label="Permalink to &quot;Time Machine {#Time-Machine}&quot;">​</a></h1><p>Every edit to a notebook is captured to a durable, content-addressed history — a built-in &quot;time machine&quot; you open with the <strong>🕘</strong> button.</p><h2 id="What-gets-recorded" tabindex="-1">What gets recorded <a class="header-anchor" href="#What-gets-recorded" aria-label="Permalink to &quot;What gets recorded {#What-gets-recorded}&quot;">​</a></h2><p>Each checkpoint stores the full serialized notebook plus per-cell digests, tagged by source:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Icon</th><th style="text-align:right;">Source</th></tr></thead><tbody><tr><td style="text-align:right;">👤</td><td style="text-align:right;">a browser edit</td></tr><tr><td style="text-align:right;">🤖</td><td style="text-align:right;">an agent edit</td></tr><tr><td style="text-align:right;">📝</td><td style="text-align:right;">an external edit (VS Code, git)</td></tr><tr><td style="text-align:right;">↩</td><td style="text-align:right;">a restore</td></tr><tr><td style="text-align:right;">🌱</td><td style="text-align:right;">the notebook opening</td></tr><tr><td style="text-align:right;">·</td><td style="text-align:right;">a periodic auto-draft</td></tr></tbody></table><p>Captures are <strong>deduplicated by content hash</strong>, so a no-op capture is free and the store stays clean. A low-frequency background snapshot guarantees an at-least-periodic capture even for changes that slip past the op-level checkpoints.</p><h2 id="Browsing-and-diffing" tabindex="-1">Browsing and diffing <a class="header-anchor" href="#Browsing-and-diffing" aria-label="Permalink to &quot;Browsing and diffing {#Browsing-and-diffing}&quot;">​</a></h2><p>The history panel lists checkpoints newest-first. Select one to see a <strong>line diff</strong> against its parent. The current state is marked; drafts are dimmed.</p><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/history-panel.png" alt=""></p><h2 id="restoring" tabindex="-1">Restoring <a class="header-anchor" href="#restoring" aria-label="Permalink to &quot;Restoring&quot;">​</a></h2><p>Restoring is <strong>non-destructive</strong>: the current state is pushed onto the undo stack and the restore is itself recorded as a new checkpoint, so you can always come straight back.</p><h2 id="Replay-—-the-buildup" tabindex="-1">Replay — the buildup <a class="header-anchor" href="#Replay-—-the-buildup" aria-label="Permalink to &quot;Replay — the buildup {#Replay-—-the-buildup}&quot;">​</a></h2><p>Press <strong>▶ Replay</strong> to step through every checkpoint in order, watching the notebook build itself up from origin to now. This is both a storytelling tool and the basis for generating the animated demos in this documentation: a headless browser replays a curated notebook&#39;s history and records it.</p><h2 id="Undo-/-redo" tabindex="-1">Undo / redo <a class="header-anchor" href="#Undo-/-redo" aria-label="Permalink to &quot;Undo / redo {#Undo-/-redo}&quot;">​</a></h2><p>Separately from the durable history, <strong>⌘Z / ⌘⇧Z</strong> provide in-session undo/redo over source snapshots for quick reversals (deferring to the editor&#39;s own text undo when a cell editor is focused).</p>',15)])])}const u=e(i,[["render",s]]);export{p as __pageData,u as default};
